const fs = require('fs');
let content = fs.readFileSync('$TMPDIR/repo-snapshot-clean.json', 'utf8');
content = content.replace(/\n\[INFO\].*$/m, '');
const snap = JSON.parse(content);

// Build a directory tree summary
// Group files into meaningful directory buckets (max 4 levels deep)
const tree = {};
snap.files.forEach(f => {
  const parts = f.relativePath.split('/');
  // Use up to depth 6 for grouping
  const depth = Math.min(parts.length - 1, 6);
  const dir = parts.slice(0, depth).join('/');
  if (!tree[dir]) tree[dir] = { files: 0, lines: 0, largest: [], samples: [] };
  tree[dir].files++;
  tree[dir].lines += f.lineCount;
  if (f.lineCount > 200) {
    tree[dir].largest.push({ p: f.relativePath, l: f.lineCount });
  }
});

// Sort largest files per dir
Object.values(tree).forEach(d => {
  d.largest = d.largest.sort((a,b)=>b.l-a.l).slice(0,3);
});

// Only include dirs with files
const summary = Object.entries(tree)
  .filter(([,v]) => v.files > 0)
  .sort((a,b) => b[1].files - a[1].files)
  .slice(0, 200)  // top 200 dirs
  .map(([dir, v]) => ({ dir, files: v.files, lines: v.lines, largest: v.largest }));

const str = JSON.stringify({ totalFiles: snap.totalFiles, totalLines: snap.totalLines, dirs: summary });
fs.writeFileSync('$TMPDIR/repo-summary.json', str);
console.log('Summary size:', str.length, 'bytes (~', Math.round(str.length/1024), 'KB)');
console.log('Dir count:', summary.length);
" 2>&1

