1	// graph-validation owns the "does this look like a graph" contract.
2	//
3	// The @claudemap-architect subagent returns free-form text that usually wraps
4	// the JSON payload in code fences and prose. parseGraphResponse does two
5	// passes: first it strips fences and tries the whole body, then it extracts
6	// the first {...} block if that fails. Both passes feed validateGraph, which
7	// enforces node/edge shape invariants the renderer relies on.
8	//
9	// validateGraph is exported too because the heuristic path also runs its
10	// output through it before shipping, so any invariant we add here protects
11	// every enrichment surface at once.
12	
13	function stripCodeFences(responseText) {
14	  return responseText
15	    .trim()
16	    .replace(/^```(?:json)?\s*/i, '')
17	    .replace(/\s*```$/i, '')
18	    .trim()
19	}
20	
21	function extractFirstJSONObject(responseText) {
22	  const start = responseText.indexOf('{')
23	  const end = responseText.lastIndexOf('}')
24	
25	  if (start === -1 || end === -1 || end <= start) {
26	    return responseText
27	  }
28	
29	  return responseText.slice(start, end + 1)
30	}
31	
32	export function validateGraph(graph) {
33	  if (!graph || !Array.isArray(graph.nodes) || !Array.isArray(graph.edges)) {
34	    throw new Error('Graph payload must include nodes[] and edges[]')
35	  }
36	
37	  for (const node of graph.nodes) {
38	    if (!node || typeof node !== 'object') {
39	      throw new Error('Graph nodes must be objects')
40	    }
41	
42	    if (!node.id || !node.label || !node.type) {
43	      throw new Error('Graph nodes require id, label, and type')
44	    }
45	
46	    if (!Object.prototype.hasOwnProperty.call(node, 'parentId')) {
47	      throw new Error(`Graph node ${node.id} is missing parentId`)
48	    }
49	
50	    if (!Object.prototype.hasOwnProperty.call(node, 'filePath')) {
51	      throw new Error(`Graph node ${node.id} is missing filePath`)
52	    }
53	  }
54	
55	  for (const edge of graph.edges) {
56	    if (!edge?.id || !edge?.source || !edge?.target || !edge?.type) {
57	      throw new Error('Graph edges require id, source, target, and type')
58	    }
59	  }
60	
61	  return graph
62	}
63	
64	export function parseGraphResponse(responseText) {
65	  const candidates = [
66	    stripCodeFences(responseText),
67	    extractFirstJSONObject(stripCodeFences(responseText)),
68	  ]
69	  let lastError = null
70	
71	  for (const candidate of candidates) {
72	    try {
73	      return validateGraph(JSON.parse(candidate))
74	    } catch (error) {
75	      lastError = error
76	    }
77	  }
78	
79	  throw lastError || new Error('Unable to parse graph response')
80	}
81

