// Map files to systems
const filesBySystem = {};
snap.files.forEach(f => {
  const sysId = getSystemId(f.relativePath);
  if (!filesBySystem[sysId]) filesBySystem[sysId] = [];
  filesBySystem[sysId].push(f);
});

