  const sys = systemDefs.find(s => s.id === sysId);
  if (!sys || !sys.parentId) return [];
  return [sys.parentId, ...getAncestors(sys.parentId)];
}

snap.files.forEach(f => {
  const sysId = getSystemId(f.relativePath);
  systemLineCounts[sysId] = (systemLineCounts[sysId] || 0) + f.lineCount;
  getAncestors(sysId).forEach(ancestor => {
    systemLineCounts[ancestor] = (systemLineCounts[ancestor] || 0) + f.lineCount;
  });
});

// Build system nodes
systemDefs.forEach(s => {
  const files = [];
  // Collect all files in this system and descendants for health check
  const collectFiles = (id) => {
    (filesBySystem[id] || []).forEach(f => files.push(f));
    systemDefs.filter(c => c.parentId === id).forEach(c => collectFiles(c.id));
  };
  collectFiles(s.id);

  const [health, healthReason] = files.length > 0 ? systemHealth(files) : ['green', null];
  const node = {
    id: s.id,
    label: s.label,
    type: 'system',
    icon: s.icon,
    parentId: s.parentId,
    filePath: s.filePath,
    lineCount: systemLineCounts[s.id] || 0,
    health,
  };
  if (s.summary) node.summary = s.summary;
  if (healthReason) node.healthReason = healthReason;
  nodes.push(node);
});

// Build file nodes
snap.files.forEach(f => {
  const sysId = getSystemId(f.relativePath);
  const [health, healthReason] = fileHealth(f);
  const node = {
    id: fileSlug(f.relativePath),
    label: f.name,
    type: 'file',
    icon: 'file',
    parentId: sysId,
    filePath: f.relativePath,
    lineCount: f.lineCount,
    health,
  };
  if (healthReason) node.healthReason = healthReason;
  nodes.push(node);
});

// Build cross-system edges from imports
const fileToSystem = {};
snap.files.forEach(f => {
  fileToSystem[f.relativePath] = getSystemId(f.relativePath);
});

// Helper to find the top-level system for a system ID
function topLevelSystem(sysId) {
  const sys = systemDefs.find(s => s.id === sysId);
  if (!sys || !sys.parentId) return sysId;
  return topLevelSystem(sys.parentId);
}

snap.files.forEach(f => {
  if (!f.imports) return;
  const srcTop = topLevelSystem(getSystemId(f.relativePath));
  f.imports.forEach(imp => {
    // Only internal relative imports
    if (!imp.startsWith('.')) return;
    // For cross-system edges, we'd need to resolve paths — skip for now
    // Instead emit edges between systems based on known cross-domain imports
  });
});

// Add curated cross-system edges based on known architecture
const knownEdges = [
  ['system-my-account-web', 'system-lib-session'],
  ['system-my-account-web', 'system-lib-tracing'],
  ['system-my-account-web', 'system-lib-apollo'],
  ['system-smart-tips-api', 'system-lib-tracing'],
  ['system-maw-server', 'system-lib-session'],
  ['system-maw-server', 'system-lib-tracing'],
  ['system-maw-pages', 'system-maw-lib'],
  ['system-maw-pages', 'system-maw-components'],
  ['system-domains', 'system-maw-lib'],
  ['system-domains', 'system-maw-components'],
];

knownEdges.forEach(([src, tgt]) => {
  const key = `${src}||${tgt}`;
  if (edgeSet.has(key) || src === tgt) return;
  edgeSet.add(key);
  edges.push({ id: `edge-${src}-${tgt}`, source: src, target: tgt, type: 'imports' });
});

const graph = { nodes, edges };
const outPath = '/Users/dumitruvulpe/uw/.claude/skills/claudemap-runtime/tmp/claudemap-enrichment.json';
writeFileSync(outPath, JSON.stringify(graph, null, 2));
console.log('Nodes:', nodes.length, '(systems:', systemDefs.length, ', files:', snap.files.length, ')');
console.log('Edges:', edges.length);
console.log('Written to:', outPath);

