import { readFileSync, writeFileSync, readdirSync, statSync } from 'fs';
import { join, extname, relative, basename } from 'path';

// ── helpers ──────────────────────────────────────────────────────────────────

function slugify(s) {
  return String(s).toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');
}
function fileSlug(rel) { return 'file-' + slugify(rel); }

function fileHealth(lineCount, importCount) {
  if (lineCount > 500) return ['red', `${lineCount} lines — too large`];
  if (lineCount > 300) return ['yellow', `${lineCount} lines — large`];
  if (importCount > 12) return ['yellow', `${importCount} imports`];
  return ['green', null];
}
function systemHealth(files) {
  const max = Math.max(0, ...files.map(f => f.lineCount));
  if (max > 500) return ['red', 'contains 500+ line files'];
  if (max > 300) return ['yellow', 'contains large files'];
  return ['green', null];
}

// ── walk all files in a dir ──────────────────────────────────────────────────

const SKIP_DIRS = new Set(['.git', 'node_modules', 'vendor', '__pycache__', '.core']);
const SKIP_EXTS = new Set(['.sum', '.png', '.jpg', '.svg', '.woff', '.woff2', '.ttf', '.ico',
  '.lock', '.map', '.min.js', '.snap', '.pdf', '.zip', '.gz', '.tar']);
const LANG_BY_EXT = {
  '.go': 'go', '.ts': 'typescript', '.tsx': 'typescript', '.js': 'javascript',
  '.jsx': 'javascript', '.mjs': 'javascript', '.cjs': 'javascript',
  '.mts': 'typescript', '.cts': 'typescript', '.py': 'python',
  '.proto': 'protobuf', '.graphql': 'graphql', '.gql': 'graphql',
  '.yaml': 'yaml', '.yml': 'yaml', '.sh': 'shell', '.md': 'markdown',
};

function walkFiles(dir, rootDir) {
  const results = [];
  function walk(current) {
    let entries;
    try { entries = readdirSync(current, { withFileTypes: true }); } catch { return; }
    for (const e of entries) {
      if (SKIP_DIRS.has(e.name)) continue;
      const full = join(current, e.name);
      if (e.isDirectory()) { walk(full); continue; }
      const ext = extname(e.name).toLowerCase();
      if (SKIP_EXTS.has(ext)) continue;
      const lang = LANG_BY_EXT[ext];
      if (!lang) continue;
      let content = '', lineCount = 0, importCount = 0;
      try {
        content = readFileSync(full, 'utf8');
        lineCount = content.split('\n').length;
        // count imports for Go
        if (lang === 'go') importCount = (content.match(/^\s+"[^"]+"/gm) || []).length;
      } catch { continue; }
      results.push({
        relativePath: relative(rootDir, full).replace(/\\/g, '/'),
        name: e.name,
        lineCount,
        importCount,
        language: lang,
      });
    }
  }
  walk(dir);
  return results;
}

// ── JS/TS snapshot (existing) ────────────────────────────────────────────────

let jsContent = readFileSync(process.env.TMPDIR + '/repo-snapshot-clean.json', 'utf8');
jsContent = jsContent.replace(/\n\[INFO\].*$/m, '');
const jsSnap = JSON.parse(jsContent);
const jsFiles = jsSnap.files.map(f => ({
  relativePath: f.relativePath,
  name: f.name,
  lineCount: f.lineCount,
  importCount: (f.imports || []).length,
  language: f.language,
}));

// ── Go/proto snapshot (telecom-mobile) ──────────────────────────────────────

const repoRoot = '/Users/dumitruvulpe/uw';
const goFiles = walkFiles(join(repoRoot, 'telecom-mobile'), repoRoot)
  .filter(f => !f.relativePath.includes('telecom-mobile/pkg/generated/'));

