  if (s.summary) node.summary = s.summary;
  if (healthReason) node.healthReason = healthReason;
  nodes.push(node);
});

// File nodes
allFiles.forEach(f => {
  const sysId = getSystemId(f.relativePath);
  const [health, healthReason] = fileHealth(f.lineCount, f.importCount);
  const node = {
    id: fileSlug(f.relativePath), label: f.name, type: 'file', icon: 'file',
    parentId: sysId, filePath: f.relativePath, lineCount: f.lineCount, health,
  };
  if (healthReason) node.healthReason = healthReason;
  nodes.push(node);
});

// Cross-system edges
const knownEdges = [
  ['system-my-account-web', 'system-lib-session'],
  ['system-my-account-web', 'system-lib-tracing'],
  ['system-my-account-web', 'system-lib-apollo'],
  ['system-maw-server', 'system-lib-session'],
  ['system-maw-server', 'system-lib-tracing'],
  ['system-maw-pages', 'system-maw-lib'],
  ['system-maw-pages', 'system-maw-components'],
  ['system-domains', 'system-maw-lib'],
  ['system-domains', 'system-maw-components'],
  ['system-tm-sim', 'system-tm-pkg-domain'],
  ['system-tm-porting', 'system-tm-pkg-network'],
  ['system-tm-tariff', 'system-tm-pkg-billing'],
  ['system-tm-tariff', 'system-tm-pkg-domain'],
  ['system-tm-roaming', 'system-tm-pkg-billing'],
  ['system-tm-lifecycle', 'system-tm-pkg-domain'],
  ['system-tm-graphql', 'system-tm-pkg-domain'],
  ['system-tm-graphql', 'system-tm-protos'],
  ['system-tm-ee-gateway', 'system-tm-pkg-network'],
  ['system-tm-crm', 'system-tm-pkg-infra'],
];
knownEdges.forEach(([src, tgt]) => {
  const key = `${src}||${tgt}`;
  if (edgeSet.has(key)) return;
  edgeSet.add(key);
  edges.push({ id: `edge-${src}-${tgt}`, source: src, target: tgt, type: 'imports' });
});

const graph = { nodes, edges };
const outPath = (process.env.TMPDIR || '/tmp') + '/claudemap-enrichment.json';
writeFileSync(outPath, JSON.stringify(graph));
console.log(`Nodes: ${nodes.length} (${systemDefs.length} systems, ${allFiles.length} files)`);
console.log(`Edges: ${edges.length}`);
console.log(`Written to: ${outPath}`);

