// ── getSystemId ──────────────────────────────────────────────────────────────

function getSystemId(rel) {
  // kubernetes
  if (rel.startsWith('kubernetes-manifests/')) return 'system-kubernetes';
  // telecom-mobile-manifests
  if (rel.startsWith('telecom-mobile-manifests/')) return 'system-kubernetes';
  // documentation
  if (rel.startsWith('documentation/')) return 'system-tooling';

  // telecom-mobile
  if (rel.startsWith('telecom-mobile/')) {
    const rest = rel.slice('telecom-mobile/'.length);
    // protos
    if (rest.startsWith('protos/')) return 'system-tm-protos';
    if (rest.startsWith('buf/')) return 'system-tm-protos';
    // pkg
    if (rest.startsWith('pkg/')) {
      const pkg = rest.split('/')[1];
      const billing = new Set(['bill','billtariffs','retailcharge','transactionlogs','promocode']);
      const network = new Set(['nexus','nexus_gateway','unicomconnectormodels','mccmnc','location']);
      const infra = new Set(['auth','clioption','libdry','retrier','scheduler','testutils',
        'jtcutils','utils','s3fetcher','s3uploader','temporalstore','integration_sdk','eventhold']);
      const domain = new Set(['esim','handsetdb','handseteligibility','imeiutil','ordering',
        'quoting','simactivationapi','simsettings','tariffcat','tariffdb','featureflags',
        'graphql','deprecated']);
      if (billing.has(pkg)) return 'system-tm-pkg-billing';
      if (network.has(pkg)) return 'system-tm-pkg-network';
      if (infra.has(pkg)) return 'system-tm-pkg-infra';
      if (domain.has(pkg)) return 'system-tm-pkg-domain';
      return 'system-tm-pkg-infra';
    }
    // cmd
    if (rest.startsWith('cmd/')) return 'system-tm-cmd';
    // docker/scripts/config
    if (rest.startsWith('docker/') || rest.startsWith('.github/') || rest.startsWith('.core/')) return 'system-tm-infra';
    // services
    if (rest.startsWith('services/')) {
      const svcName = rest.split('/')[1];
      return serviceGroup(svcName);
    }
    // root files (go.mod, generate.go, docker-compose, etc.)
    return 'system-tm-infra';
  }

  // js-mono libs
  if (rel.startsWith('js-mono/libs/fastify-uw-session-plugin/')) return 'system-lib-session';
  if (rel.startsWith('js-mono/libs/tracing/')) return 'system-lib-tracing';
  if (rel.startsWith('js-mono/libs/apollo/')) return 'system-lib-apollo';
  if (rel.startsWith('js-mono/libs/')) return 'system-tooling';
  if (rel.startsWith('js-mono/tools/') || rel.startsWith('js-mono/scripts/')) return 'system-tooling';
  if (rel === 'js-mono/.prettierrc.js') return 'system-tooling';

  // js-mono apps
  if (rel.startsWith('js-mono/apps/smart-tips-graphql/')) return 'system-smart-tips-api';
  if (rel.startsWith('js-mono/apps/game-of-thrones-api/')) return 'system-got-api';
  if (rel.startsWith('js-mono/apps/my-account-web-e2e/')) return 'system-e2e';

  // my-account-web domains
  const maw = 'js-mono/apps/my-account-web/src/domains/';
  if (rel.startsWith(maw + 'auth/')) return 'system-domain-auth';
  if (rel.startsWith(maw + 'account/')) return 'system-domain-account';
  if (rel.startsWith(maw + 'billing/')) return 'system-domain-billing';
  if (rel.startsWith(maw + 'payments/')) return 'system-domain-payments';
  if (rel.startsWith(maw + 'cashback/')) return 'system-domain-cashback';
  if (rel.startsWith(maw + 'insurance/')) return 'system-domain-insurance';
  if (rel.startsWith(maw + 'energy/smart-booking/')) return 'system-domain-energy-smartbooking';
  if (rel.startsWith(maw + 'energy/meter-reads/')) return 'system-domain-energy-meterreads';
  if (rel.startsWith(maw + 'energy/ev-switch/')) return 'system-domain-energy-evswitch';
  if (rel.startsWith(maw + 'energy/')) return 'system-domain-energy';
  if (rel.startsWith(maw + 'mobile/')) return 'system-domain-mobile';
  if (rel.startsWith(maw + 'fixed-line/')) return 'system-domain-fixedline';
  if (rel.startsWith(maw + 'home/')) return 'system-domain-home';
  if (rel.startsWith(maw + 'debt/')) return 'system-domain-debt';
  if (rel.startsWith(maw)) return 'system-domain-other';

  if (rel.startsWith('js-mono/apps/my-account-web/server/')) return 'system-maw-server';
  if (rel.startsWith('js-mono/apps/my-account-web/src/components/')) return 'system-maw-components';
  if (rel.startsWith('js-mono/apps/my-account-web/src/pages/')) return 'system-maw-pages';
  if (rel.startsWith('js-mono/apps/my-account-web/src/')) return 'system-maw-lib';
  if (rel.startsWith('js-mono/apps/my-account-web/')) return 'system-maw-config';

  return 'system-tooling';
}

